+        assert_eq!(format_bytes(1024), "1.0KB");
+        assert_eq!(format_bytes(1536), "1.5KB");
+        assert_eq!(format_bytes(1048576), "1.0MB");
+        assert_eq!(format_bytes(1073741824), "1.0GB");
+        assert_eq!(format_bytes(1099511627776), "1.0TB");
